import { scaleSequential } from "d3-scale";
import {
	interpolateBuGn,
	interpolateBuPu,
	interpolateCool,
	interpolateCubehelixDefault,
	interpolateGnBu,
	interpolateInferno,
	interpolateMagma,
	interpolateOrRd,
	interpolatePlasma,
	interpolatePuBu,
	interpolatePuBuGn,
	interpolatePuRd,
	interpolateRdPu,
	interpolateViridis,
	interpolateWarm,
	interpolateYlGn,
	interpolateYlGnBu,
	interpolateYlOrBr,
	interpolateYlOrRd,
} from "d3-scale-chromatic";
import {
	interpolateHcl,
	interpolateHsl,
	interpolateLab,
	interpolateRgb,
	interpolateRgbBasis,
} from "d3-interpolate";
import { binnedScale } from "../common/binning.js";
import { getDomain } from "../common/domain.js";
import {
	CARROTS,
	FLOURISH_BLUES,
	FLOURISH_GREENS,
	FLOURISH_GREYS,
	FLOURISH_ORANGES,
	FLOURISH_PINKS,
	FLOURISH_PURPLES,
	FLOURISH_REDS,
	FLOURISH_TEALS,
	FLOURISH_YELLOWS,
} from "./colorSamples.js";

var INTERPOLATORS = Object.freeze({
	BuGn: interpolateBuGn,
	BuPu: interpolateBuPu,
	Carrots: interpolateRgbBasis(CARROTS),
	Cool: interpolateCool,
	CubehelixDefault: interpolateCubehelixDefault,
	FlourishBlues: interpolateRgbBasis(FLOURISH_BLUES),
	FlourishGreens: interpolateRgbBasis(FLOURISH_GREENS),
	FlourishGreys: interpolateRgbBasis(FLOURISH_GREYS),
	FlourishOranges: interpolateRgbBasis(FLOURISH_ORANGES),
	FlourishPinks: interpolateRgbBasis(FLOURISH_PINKS),
	FlourishPurples: interpolateRgbBasis(FLOURISH_PURPLES),
	FlourishReds: interpolateRgbBasis(FLOURISH_REDS),
	FlourishTeals: interpolateRgbBasis(FLOURISH_TEALS),
	FlourishYellows: interpolateRgbBasis(FLOURISH_YELLOWS),
	GnBu: interpolateGnBu,
	Inferno: interpolateInferno,
	Magma: interpolateMagma,
	OrRd: interpolateOrRd,
	Plasma: interpolatePlasma,
	PuBu: interpolatePuBu,
	PuBuGn: interpolatePuBuGn,
	PuRd: interpolatePuRd,
	RdPu: interpolateRdPu,
	Viridis: interpolateViridis,
	Warm: interpolateWarm,
	YlGn: interpolateYlGn,
	YlGnBu: interpolateYlGnBu,
	YlOrBr: interpolateYlOrBr,
	YlOrRd: interpolateYlOrRd,
});

var INTERPOLATOR_GENERATORS = {
	hcl: interpolateHcl,
	hsl: interpolateHsl,
	lab: interpolateLab,
	rgb: interpolateRgb,
};

function getCustomInterpolator(state) {
	var color_space = state.sequential_color_space;
	var min = state.sequential_custom_min;
	var max = state.sequential_custom_max;
	return INTERPOLATOR_GENERATORS[color_space](min, max);
}

function getSequentialFunction(state, values) {
	var domain = state.sequential_custom_domain
		? [state.sequential_domain_min, state.sequential_domain_max]
		: getDomain(values);
	var colorInterpolator = function (t) {
		var interpolation =
			INTERPOLATORS[state.sequential_palette] || getCustomInterpolator(state);
		if (state.sequential_reverse) return interpolation(1 - t);
		else return interpolation(t);
	};

	if (state.binning)
		return binnedScale(state, domain, values, colorInterpolator);

	var scale = scaleSequential(colorInterpolator).domain(domain);
	var colorScale = function (value) {
		return isNaN(value) || value === null ? null : scale(value);
	};
	colorScale.domain = Object.freeze(domain);

	return colorScale;
}

export { getSequentialFunction };
